import hashlib, shutil
from pathlib import Path

def get_cache_key(text: str, voice: str, speed: float, model: str) -> str:
    content = f"{text}|{voice}|{speed}|{model}"
    return hashlib.sha256(content.encode()).hexdigest()

def cached_path(cache_dir: str, key: str, fmt: str = "mp3") -> str | None:
    p = Path(cache_dir) / f"{key}.{fmt}"
    return str(p) if p.exists() else None
